const html = $input.first().json.html;

if (!html) {
  return [{ json: { error: "No HTML found" } }];
}

// Extraer todas las tablas
const tableMatches = html.match(/<table[\s\S]*?<\/table>/gi) || [];

const tables = tableMatches.map(tableHtml => {
  const rows = [];
  const rowMatches = tableHtml.match(/<tr[\s\S]*?<\/tr>/gi) || [];

  rowMatches.forEach(rowHtml => {
    const cells = [];
    const cellMatches = rowHtml.match(/<(td|th)[\s\S]*?<\/(td|th)>/gi) || [];

    cellMatches.forEach(cell => {
      const text = cell
        .replace(/<[^>]+>/g, '')
        .replace(/\s+/g, ' ')
        .trim();
      cells.push(text);
    });

    if (cells.length) rows.push(cells);
  });

  return rows;
});

return [{
  json: {
    tables,
    tablesFound: tables.length
  }
}];

const output = [];

for (const item of items) {

  const source = item.json;

  let foundArrays = [];

  for (const key in source) {
    if (Array.isArray(source[key])) {
      foundArrays = foundArrays.concat(source[key]);
    }
  }

  output.push({
    json: {
      services: foundArrays,
      totalFound: foundArrays.length
    }
  });

}

return output;

