// Filtra solo items con binario .xlsx y normaliza la key a "attachment"

const results = [];

for (const item of $input.all()) {
  const binaryData = item.binary || {};

  for (const key of Object.keys(binaryData)) {
    const bin = binaryData[key];
    const filename = bin.fileName || "";
    const mimeType = bin.mimeType || "";

    if (!filename.toLowerCase().endsWith(".xlsx")) continue;
    if (mimeType && mimeType.toLowerCase().indexOf("spreadsheetml") === -1) continue;

    results.push({
      json: item.json,
      binary: {
        attachment: bin
      }
    });
    break;
  }
}

if (results.length === 0) {
  return [{ json: { message: "No se encontraron archivos .xlsx" } }];
}

return results;

// Tomar todos los items del nodo anterior
